"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[755],{9523:e=>{e.exports=JSON.parse('{"functions":[{"name":"event","desc":"Triggers an admin abuse event across all servers. The event is identified by its\\nkey from the Events module.\\n\\nWhen called, this function:\\n1. Validates the event key and its Executor\\n2. Persists the event end-time in MemoryStoreService via the Ping module\\n3. Broadcasts the event to all servers via MessagingService\\n4. Activates the event locally (re-triggers if the same event is already active)\\n\\n```lua\\nAdminAbuse.event(\\"SixSeven\\")\\n```","params":[{"name":"eventKey","desc":"The key identifying which event to trigger","lua_type":"string"}],"returns":[],"function_type":"static","since":"0.1.0","source":{"line":101,"path":"packages/admin-abuse/src/init.luau"}}],"properties":[{"name":"onEventChanged","desc":"A Signal that fires whenever a new admin event begins executing. The callback\\nreceives the event key as its only argument.\\n\\n```lua\\nAdminAbuse.onEventChanged:Connect(function(eventKey: string)\\n\\tprint(\\"New event:\\", eventKey)\\nend)\\n```","lua_type":"Signal","since":"0.1.0","source":{"line":140,"path":"packages/admin-abuse/src/init.luau"}},{"name":"EventMultipliers","desc":"Reference to the [EventMultipliers] module. Holds observable State objects\\nthat represent gameplay multipliers which can be set by event Executors and\\nobserved by other game systems.\\n\\n```lua\\nlocal multiplier = AdminAbuse.EventMultipliers.ResourceNodeMultiplier:Get()\\n```","lua_type":"EventMultipliers","since":"0.1.0","source":{"line":156,"path":"packages/admin-abuse/src/init.luau"}},{"name":"Events","desc":"Reference to the Events module. Contains the table of registered events keyed\\nby their `GlobalEventKey`. Each event entry has an `Executor` function.","lua_type":"Events","since":"0.1.0","source":{"line":167,"path":"packages/admin-abuse/src/init.luau"}}],"types":[],"name":"AdminAbuse","desc":"The main entry point for the Admin Abuse package. Provides a simple API to trigger\\ntimed events that automatically synchronize across all active game servers.\\n\\n**Install via Wally:**\\n```toml\\n[dependencies]\\nAdminAbuse = \\"kestrel/admin-abuse@0.1.0\\"\\n```\\n\\n**Basic usage:**\\n```lua\\nlocal AdminAbuse = require(path.to.AdminAbuse)\\n\\n-- Trigger an event on every server\\nAdminAbuse.event(\\"SixSeven\\")\\n\\n-- React to event changes\\nAdminAbuse.onEventChanged:Connect(function(eventKey)\\n\\tprint(\\"Event activated:\\", eventKey)\\nend)\\n```\\n\\nOn require, the module subscribes to MessagingService to receive events broadcast\\nby other servers. The subscription retries up to 2 times with a 5-second delay\\nbetween attempts if it fails.","realm":["Server"],"since":"0.1.0","source":{"line":35,"path":"packages/admin-abuse/src/init.luau"}}')}}]);